import{_ as e,o as r,c as o,a2 as a}from"./chunks/framework.BWuWLRhz.js";const p="/images/how-religion-got-in-the-way/Religion-Cartoon.png",i="/images/how-religion-got-in-the-way/pinit_fg_en_rect_gray_20.png",c=JSON.parse('{"title":"How Religion Got in the Way","description":"","frontmatter":{"title":"How Religion Got in the Way","titleZh":"宗教如何成为阻碍","date":"2014-10-10T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/10/how-religion-got-in-the-way.html","slug":"how-religion-got-in-the-way"},"headers":[],"relativePath":"posts/how-religion-got-in-the-way.md","filePath":"posts/how-religion-got-in-the-way.md","lastUpdated":1782886257000}'),n={name:"posts/how-religion-got-in-the-way.md"};function l(h,t,s,g,w,m){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="宗教如何成为阻碍-·-how-religion-got-in-the-way" tabindex="-1">宗教如何成为阻碍 · How Religion Got in the Way <a class="header-anchor" href="#宗教如何成为阻碍-·-how-religion-got-in-the-way" aria-label="Permalink to &quot;宗教如何成为阻碍 · How Religion Got in the Way&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/10/how-religion-got-in-the-way.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/10/how-religion-got-in-the-way.html</a> · 2014-10-10</p></blockquote><h2 id="致所有对更新拖延感到抓狂的读者-为什么我没法按时更新。" tabindex="-1"><em>致所有对更新拖延感到抓狂的读者:<a href="https://waitbutwhy.com/2014/10/cant-post-on-time.html" target="_blank" rel="noreferrer">为什么我没法按时更新</a>。</em> <a class="header-anchor" href="#致所有对更新拖延感到抓狂的读者-为什么我没法按时更新。" aria-label="Permalink to &quot;*致所有对更新拖延感到抓狂的读者:[为什么我没法按时更新](https://waitbutwhy.com/2014/10/cant-post-on-time.html)。*&quot;">​</a></h2><p>&quot;睡觉前把脸洗干净,这样天使就会下来趁你睡着的时候亲你。&quot;</p><p>这是我小时候在奶奶家过夜时她告诉我的话。我大概五岁,面对这条来自权威信任源的信息,我不仅毫无违和感,而且觉得这种事别人告诉我简直再正常不过。</p><p>我是一个「鱼与熊掌兼得」的改革派犹太教家庭里的头一个孩子,这家人过圣诞节也过复活节。生在这种环境,意味着我会被灌输以下内容:</p><ul><li>每年一次,一个肥胖的中年男人会以最没效率的方式闯进我家,给我留一堆包好的礼物,然后不肯直接走大门,非要爬回烟囱上去,再让一群体型巨大、没有翅膀却会飞的哺乳动物带着他,在几个小时之内跑到另外十亿多户人家干同样的事</li><li>逾越节 (Passover) 那天,一个隐形人会在我们全家吃饭时悄悄溜进屋,因为他想喝一小杯酒</li><li>同一周,一只十英尺高、有自我意识的兔子也会闯进屋,可能是直接穿墙进来的,然后毫无理由地把它下的一堆巧克力蛋摆得到处都是</li><li>如果我掉了一颗牙,把它放在枕头底下,一个会飞的女人就会趁我睡着时闯进我卧室,以她自己定的价格把牙买走</li><li>再加上从来没人跟我解释过世上还有「虚构」这个概念,所以我一直以为芝麻街 (Sesame Street) 里的所有生物都是野外真实存在的生物学物种</li></ul><p>所以说,只因为我洗了脸,就有会飞的人闯进我房间趁我睡觉时来揩油?操,行啊,为啥不。这在当时看来完全是件寻常事——我那个世界里,这种破事儿隔三差五就发生一次。</p><p>所有这些信息,是和教我英语、告诉我形状和颜色是什么、教我怎么拉屎、以及解释盯着特别矮的成年人看是不礼貌的——这一整套启蒙一块儿打包灌给我的。</p><p>信息量确实挺大,但我处理得还不错。直到某天,剧情突然来了个让人不安的反转。他们开始告诉我,我认识的现实里的某些部分——「哦对,那些其实是完全假的。」等等。啥?我他妈就是个新手,拼死拼活想学点知识和技能,你们居然一直在耍我?更过分的是,我发现所有好玩的都是假的,所有无聊的才是真的。</p><p>我问的问题越多,这张巨大的谎言之网就越让人脑子打结。龙是假的,但恐龙是真的。国王和公主是真的,但巫师和仙女是假的。迪士尼乐园是真的,但芝麻街不是。农场里的动物确实存在,但它们是恶心、下贱的生物,行为和长相跟虚构作品里完全不一样。海盗和印第安人都是真的,但远不像我熟悉的那样卡通和种族歧视化,而女巫和鬼魂则完全是假的。摸蟾蜍不会让我长疣,我斜眼看东西眼睛不会卡住,还有,不,迈克尔·杜卡基斯 (Michael Dukakis) 并不是一个有戏的候选人,尽管他在我一年级班级投票里以 20 比 1 大获全胜。</p><p>从那以后,我只能信任自己,于是我在脑子里造了两个桶,一个叫「假」,一个叫「真」,开始把所有新信息往这两个桶里丢。</p><p>要是有什么东西没法明确归到哪个桶里,我就去问别人。有一天我问我爸关于上帝的事。「有些人信上帝,有些人不信,每个人都得自己做决定。」嗯,不。这明显是「假」桶的答案。从那以后,我就是无神论者了。对七岁的 Tim 来说,这跟说我是「无圣诞老人主义者」或「无仙女主义者」没啥两样——在这么多东西被揭穿是假的之后,我对一切看起来超自然的东西都变得愤世嫉俗。我发展出一条「如果一件事听起来爽得不像真的,那它就不是真的」的规则,那么凭什么要用不同的标准去评估上帝,而不是其他所有超自然角色?</p><p>唯一让我困惑的是,为什么我爸没像对其他很多事那样直接承认上帝是假的。他为什么在这事上这么别扭?</p><p>随着我长大,这变得更加让人费解。「如果一件事听起来爽得不像真的,那它就不是真的」这条规则硬化成了对一切不符合自然法则的东西的彻底拒绝。我人生中的每一个经历都在支持这一点,那我凭什么去质疑它?而这个世界也同意我的看法——只有一个例外。我认识的犹太人大多数都信上帝。基督徒也大多如此。比我年长、更聪明、更有智慧的人都信。就连那些并不完全确信的人,谈起这事也似乎不太自在。我几乎找不到几个人愿意直接说:「我当然不信上帝。」</p><p>为什么大家在这件事上都这么别扭?<em>到底怎么回事?</em></p><p>我了解得越多,越发现整个国家都跟我唱反调——我<a href="http://www.ropercenter.uconn.edu/public-perspective/ppscan/66/66001.pdf" target="_blank" rel="noreferrer">读到过</a>96% 的美国人信神,90% 相信天堂,73% 相信地狱,<a href="http://www.religioustolerance.org/ev_publia.htm" target="_blank" rel="noreferrer">差不多一半</a>人按字面意思相信《圣经》——会说话的蛇、诺亚方舟、活到 200 岁的人啥的——还有 61% 的人认为「一个民主国家如果没有对神或至高存在的普遍信仰,就无法存续」。我还发现,那些虔诚的信徒里甚至有一堆科学头脑的天才,比如艾萨克·牛顿 (Isaac Newton)。而与此同时,做一个无神论者是件不光彩的事,带贬义,是那种得闭嘴不说的事,尤其你要是想<a href="http://www.huffingtonpost.com/2014/05/19/presidential-poll-atheists_n_5353524.html" target="_blank" rel="noreferrer">竞选公职</a>的话。</p><p>一开始,我只是真心地感到挫败——搞不懂那么多人的核心精神动力究竟是什么——到了大学,我索性对这个话题彻底关了门。任何跟超自然世界沾边的东西——上帝、更高的力量、灵性——都跟我<em>没关系</em>。至于犹太教,我倒是乐呵呵地跟家人过节、吃巧克力金币、练就了一手用筷子吃中餐的好本领,可《托拉》?不感兴趣。除了拒斥神性之外,我也不喜欢那些有组织的宗教的行事方式。在我眼里,科学是谦逊的、协作的、不断自我修正、向前推进的;而宗教是傲慢的、制造分裂的、敌视变革的、执念于过去的。大学毕业时,我是个坚定的无神论者,带着那种只有 21 岁才幼稚到能装出来的傲慢。</p><p>当时我没意识到的是,「无神论者」根本不是一个东西。它只是「不是某个东西」。我把自己一锤定音为无神论者就完事,等于是把整个精神身份建立在了我<em>不是什么</em>上。没错,我是无神论者,可我还不是乌干达人呢。要是有人问我从哪儿来,我回答「不是乌干达」显然没啥用。同理,如果我唯一的精神身份就是「我不相信世界上那些庞大古老宗教里的神性成分」,那我在精神上其实啥也不是。</p><p>当然啦,那会儿我并不觉得精神上啥也不是有什么问题。灵性是给宗教人士准备的,而我是科学派的,所以谁在乎呢?</p><h2 id="我没意识到的是-我不小心把人类成长体验中至关重要的一部分给冲进了马桶。" tabindex="-1">我没意识到的是,我不小心把人类成长体验中至关重要的一部分给冲进了马桶。 <a class="header-anchor" href="#我没意识到的是-我不小心把人类成长体验中至关重要的一部分给冲进了马桶。" aria-label="Permalink to &quot;我没意识到的是,我不小心把人类成长体验中至关重要的一部分给冲进了马桶。&quot;">​</a></h2><p><strong>灵性到底是什么?</strong></p><p>几乎没有比<em>灵性 (spirituality)</em> 更令人反感的词了。它含糊、无形、莫名其妙地招人烦,还能同时惹毛宗教人士和非宗教人士。你要是凑齐五个都说自己挺喜欢灵性的人,他们能给这个词下出五种不同的定义。</p><p>那么,按我们今天用这个词的方式,灵性究竟是什么,我们又需要从它那儿得到什么?</p><p>自从人类物种睁开双眼进入意识状态以来,它就一直是一个好奇心爆棚的孩子,渴望把一切都搞明白。它所生活的这个世界是什么?这一切又意味着什么?</p><p>这个问题的第一部分——这个世界是什么?——成了科学的工作。第二部分——这一切意味着什么?——则是灵性的工作。</p><p>科学是我们所知道的东西,而灵性是我们如何在哲学上、心理上和情感上与这些知识共处。科学给我们信息;灵性帮助我们理解这些信息。二者像双人组合一样引领着我们,各自负责&quot;搞明白这一切&quot;这个难题里至关重要的那一半——当科学告诉我们一些惊人的事情,比如&quot;地球是绕着太阳转的,而不是反过来!&quot;我们就会瞪大眼睛,转向灵性问:&quot;这改变了什么?这该如何改变我们看待自己、看待世界、看待生活的方式?&quot;</p><p>按这个定义,灵性是一个世俗的概念,而认为灵性和科学是水火不容的这种想法是错误的——它们是同一场探索的两半。一如既往,卡尔·萨根 (Carl Sagan) <a href="https://www.amazon.com/The-Demon-Haunted-World-Science-Candle/dp/0345409469" target="_blank" rel="noreferrer">说得最好</a>:</p><blockquote><p>&quot;Spirit&quot;(灵)一词来自拉丁语,意为&quot;呼吸&quot;。我们呼吸的是空气,空气当然是物质,尽管稀薄。尽管用法上常有相反的暗示,但&quot;灵性&quot;一词并不必然意味着我们在谈论物质(包括构成大脑的物质)之外的东西,或科学领域之外的任何东西……科学不仅与灵性相容;它还是灵性的深层源泉。当我们认识到自己在光年浩瀚与岁月流转中的位置,当我们把握住生命的精巧、美丽与微妙时,那种飞升的感觉,那种既振奋又谦卑的复合感受,当然就是灵性的……认为科学和灵性在某种意义上互斥的看法,对二者都是一种伤害。</p></blockquote><p>随着人类持续学习,科学和灵性应该是协作的、创新的,并随着新发展的出现永远处于持续演化的状态、不断向前迈进。科学为人类开辟通向更高意识和智慧层次的道路,但只有通过灵性领域,我们才能成长到足以走上那些道路。</p><p>在日常层面上,大多数人面临的最大挑战之一就是努力避免生活在一种无意识的迷雾中——这种迷雾就是当你出于狭隘的理由做出重大人生决定的时候,当你目光短浅地绕开自己的原则时,当你一而再地把错的东西置于对的东西之上、因为恐惧而甘于平庸、或者在拖延中浪费大量宝贵时间时,你所处的状态。而这是科学帮不上忙的一件事——无意识的迷雾只能通过灵性成长来对抗。</p><p>这样定义之后,灵性不仅是我们生活中一个可以接受、值得拥有的领域,它对人类的成长、繁荣以及最充分地发挥大脑潜能来说,更是<em>至关重要</em>的。</p><p>那为什么在今天的世界里,灵性成长得到的严肃关注这么少?本该由灵性覆盖的那另一半探索,到底怎么了?</p><p>也许是这样: <a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Religion-Cartoon.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Religion Cartoon"></a> 这就是我认为我们灵性领域的遭遇——它被宗教用胳膊肘挤出了主流,推到了边缘地带,原因有一堆:</p><ul><li><p><strong>恐惧。</strong> 宗教用恐惧攫住人们,把他们拉进自己那个装满确定答案和永生的怀抱。不幸的是,它似乎干得并不怎么令人信服——<a href="http://www.asanet.org/images/journals/docs/pdf/asr/Dec10ASRFeature.pdf" target="_blank" rel="noreferrer">最近一项研究</a>发现,你觉得自己离上帝有多近<a href="https://www.amazon.com/gp/product/B0089LOHHO/ref=as_li_ss_tl?ie=UTF8&amp;camp=1789&amp;creative=390957&amp;creativeASIN=B0089LOHHO&amp;linkCode=as2&amp;tag=spacforrent-20" target="_blank" rel="noreferrer">对你整体的生活满意度毫无影响</a>。如果有人现在告诉我,我可以永生,而且我信了,我会比现在敲下这句话时开心得<em>多得多得多</em>。如果一个信教的人并不比我更开心,那我拒绝相信他们真的对上帝深信不疑。</p></li><li><p><strong>进化上倾向于部落主义。</strong> 社会心理学家乔纳森·海特 (Jonathan Haidt) <a href="http://ideas.time.com/2012/03/27/have-we-evolved-to-be-religious/" target="_blank" rel="noreferrer">解释得</a>很好:</p></li></ul><blockquote><p>我的意思是,我们进化出的能力让我们在周围到处看到神圣,并且和别人一起围绕神圣的物件、人物和理念结成团体。这就是为什么政治如此部落化。政治一部分是世俗的,一部分关乎自身利益。但政治也关乎神圣。它是关于和他人一起追求道德理想。它是关于善恶之间那场永恒的斗争,而我们都相信自己站在善的一边。</p></blockquote><p>这只是一个推测性的理论,但在社会科学里有相当多的支持。而且它讲得通。相信一个比你自己更大的东西,并因此和你的族人产生纽带,会让你更愿意合作,而随着时间推移,那些具备这种倾向的部落就会比不那么倾向于崇拜神圣事物的部落繁荣起来。合作是蚂蚁和蜜蜂的绝妙物种生存工具,那对人类为什么就不是呢?</p><ul><li><p><strong>进化上倾向于相信神明。</strong> 与上面那条类似、也没被完全证实的一种理论认为,那些恰好更倾向于相信神明的人类部落会更诚实、更利他、更愿意合作,因为他们相信自己正在被注视。随着时间推移,这些部落会活得更好——也就是说,他们是我们的祖先,而不是那些无神论部落。<a href="#footnote-1-2597">1</a></p></li><li><p><strong>西格蒙德·弗洛伊德 (Sigmund Freud) <a href="http://www.scandalon.co.uk/philosophy/psychology.htm" target="_blank" rel="noreferrer">认为</a>,很多人寻找上帝,是为了让祂充当一个强大的父亲形象。<a href="#footnote-2-2597">2</a></strong></p></li></ul><p>在这些势力面前,那种微妙的、世俗的灵性根本没机会登上大舞台。而且宗教也让它在小的、个体的舞台上举步维艰。灵性经常两头受气——非宗教人士忽视它,因为他们不公平地把它归到&quot;不适合我&quot;那一堆里,当作对宗教的一并拒绝;宗教人士也忽视它,因为他们指望自己的宗教来提供灵性成长,而宗教通常并不聚焦于我们一直在讨论的这类灵性。</p><p>但我们上面刚刚确认了灵性成长很重要——<em>真的</em>很重要——那么现在怎么办?</p><p>我们需要一些好的、简单的、可及的、不惹人烦的、能长期坚持的方式,让个体去接近灵性。我认为这要从一个能跟你合拍、能作为你灵性向导的灵性框架开始。我恰好脑子里就有一个,对我而言效果一直不错(而且不知不觉地,它已经贴满了这个博客一篇又一篇的文章里)。我们下一篇再聊。<a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">下一篇</a>。</p><hr><p>如果你喜欢 Wait But Why,订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>关于这一点的<a href="http://www.npr.org/templates/story/story.php?storyId=129528196&amp;ft=1&amp;f=1016" target="_blank" rel="noreferrer">有趣文章</a>。<a href="#note-1-2597">↩</a></p></li><li><p>他当然会这么想。<a href="#note-2-2597">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/10/how-religion-got-in-the-way.html&amp;description=How%20Religion%20Got%20in%20the%20Way" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p>',48)])])}const f=e(n,[["render",l]]);export{c as __pageData,f as default};
